/**
 * ГЕНЕРАТОРЫ АВТОМОБИЛЬНЫХ КОМПОНЕНТОВ
 */
const AutoPartsGenerator = {
    /**
     * Генерация свечи зажигания
     * Формат зависит от бренда
     */
    generateSparkPlug: (payload) => {
        const brandKeys = Object.keys(AutoPartsDictionaries.sparkPlugs.brands);
        const brandIdx = payload % brandKeys.length;
        const brandKey = brandKeys[brandIdx];
        const brand = AutoPartsDictionaries.sparkPlugs.brands[brandKey];
        
        let result, encoded;
        
        if (brandKey === 'bosch') {
            const prefixIdx = Math.floor(payload / brandKeys.length) % brand.prefixes.length;
            const seriesIdx = Math.floor(payload / (brandKeys.length * brand.prefixes.length)) % brand.series.length;
            const suffixIdx = Math.floor(payload / (brandKeys.length * brand.prefixes.length * brand.series.length)) % brand.suffixes.length;
            
            const bases = [brandKeys.length, brand.prefixes.length, brand.series.length, brand.suffixes.length];
            const indices = [brandIdx, prefixIdx, seriesIdx, suffixIdx];
            encoded = EncodingUtils.encodeMultiDimensional(indices, bases);
            const withChecksum = EncodingUtils.addChecksum(encoded ^ payload);
            
            result = brand.format(brand.prefixes[prefixIdx], brand.series[seriesIdx], brand.suffixes[suffixIdx]);
            return `${brand.name} ${result} SPK-${EncodingUtils.toBase36(withChecksum)}`;
            
        } else if (brandKey === 'ngk') {
            const prefixIdx = Math.floor(payload / brandKeys.length) % brand.prefixes.length;
            const heatIdx = Math.floor(payload / (brandKeys.length * brand.prefixes.length)) % brand.heatRanges.length;
            const suffixIdx = Math.floor(payload / (brandKeys.length * brand.prefixes.length * brand.heatRanges.length)) % brand.suffixes.length;
            
            const bases = [brandKeys.length, brand.prefixes.length, brand.heatRanges.length, brand.suffixes.length];
            const indices = [brandIdx, prefixIdx, heatIdx, suffixIdx];
            encoded = EncodingUtils.encodeMultiDimensional(indices, bases);
            const withChecksum = EncodingUtils.addChecksum(encoded ^ payload);
            
            result = brand.format(brand.prefixes[prefixIdx], brand.heatRanges[heatIdx], brand.suffixes[suffixIdx]);
            return `${brand.name} ${result} SPK-${EncodingUtils.toBase36(withChecksum)}`;
            
        } else if (brandKey === 'denso') {
            const prefixIdx = Math.floor(payload / brandKeys.length) % brand.prefixes.length;
            const suffixIdx = Math.floor(payload / (brandKeys.length * brand.prefixes.length)) % brand.suffixes.length;
            
            const bases = [brandKeys.length, brand.prefixes.length, brand.suffixes.length];
            const indices = [brandIdx, prefixIdx, suffixIdx];
            encoded = EncodingUtils.encodeMultiDimensional(indices, bases);
            const withChecksum = EncodingUtils.addChecksum(encoded ^ payload);
            
            result = brand.format(brand.prefixes[prefixIdx], brand.suffixes[suffixIdx]);
            return `${brand.name} ${result} SPK-${EncodingUtils.toBase36(withChecksum)}`;
            
        } else {
            // Champion, Beru и другие
            const prefixIdx = Math.floor(payload / brandKeys.length) % brand.prefixes.length;
            const seriesIdx = Math.floor(payload / (brandKeys.length * brand.prefixes.length)) % brand.series.length;
            const suffixIdx = Math.floor(payload / (brandKeys.length * brand.prefixes.length * brand.series.length)) % brand.suffixes.length;
            
            const bases = [brandKeys.length, brand.prefixes.length, brand.series.length, brand.suffixes.length];
            const indices = [brandIdx, prefixIdx, seriesIdx, suffixIdx];
            encoded = EncodingUtils.encodeMultiDimensional(indices, bases);
            const withChecksum = EncodingUtils.addChecksum(encoded ^ payload);
            
            result = brand.format(brand.prefixes[prefixIdx], brand.series[seriesIdx], brand.suffixes[suffixIdx]);
            return `${brand.name} ${result} SPK-${EncodingUtils.toBase36(withChecksum)}`;
        }
    },

    /**
     * Генерация фильтра
     * Формат: Brand Type-Series[Suffix] FLT-CODE
     */
    generateFilter: (payload) => {
        const brandKeys = Object.keys(AutoPartsDictionaries.filters.brands);
        const brandIdx = payload % brandKeys.length;
        const brandKey = brandKeys[brandIdx];
        const brand = AutoPartsDictionaries.filters.brands[brandKey];
        
        const typeKeys = Object.keys(brand.types);
        const typeIdx = Math.floor(payload / brandKeys.length) % typeKeys.length;
        const typeKey = typeKeys[typeIdx];
        const type = brand.types[typeKey];
        
        const prefixIdx = Math.floor(payload / (brandKeys.length * typeKeys.length)) % type.prefixes.length;
        const seriesIdx = Math.floor(payload / (brandKeys.length * typeKeys.length * type.prefixes.length)) % type.series.length;
        const suffixIdx = Math.floor(payload / (brandKeys.length * typeKeys.length * type.prefixes.length * type.series.length)) % brand.suffixes.length;
        
        const bases = [brandKeys.length, typeKeys.length, type.prefixes.length, type.series.length, brand.suffixes.length];
        const indices = [brandIdx, typeIdx, prefixIdx, seriesIdx, suffixIdx];
        const encoded = EncodingUtils.encodeMultiDimensional(indices, bases);
        const withChecksum = EncodingUtils.addChecksum(encoded ^ payload);
        const code = EncodingUtils.toBase36(withChecksum);
        
        const partNumber = `${type.prefixes[prefixIdx]} ${type.series[seriesIdx]}${brand.suffixes[suffixIdx]}`;
        return `${brand.name} ${partNumber} FLT-${code}`;
    },

    /**
     * Генерация кода двигателя
     * Формат зависит от производителя
     */
    generateEngine: (payload) => {
        const brandKeys = Object.keys(AutoPartsDictionaries.engines);
        const brandIdx = payload % brandKeys.length;
        const brandKey = brandKeys[brandIdx];
        const brand = AutoPartsDictionaries.engines[brandKey];
        
        let result, encoded;
        
        if (brandKey === 'toyota') {
            const familyIdx = Math.floor(payload / brandKeys.length) % brand.families.length;
            const suffixIdx = Math.floor(payload / (brandKeys.length * brand.families.length)) % brand.suffixes.length;
            
            const bases = [brandKeys.length, brand.families.length, brand.suffixes.length];
            const indices = [brandIdx, familyIdx, suffixIdx];
            encoded = EncodingUtils.encodeMultiDimensional(indices, bases);
            const withChecksum = EncodingUtils.addChecksum(encoded ^ payload);
            
            result = `${brand.families[familyIdx]}${brand.suffixes[suffixIdx]}`;
            return `${brand.name} ${result} ENG-${EncodingUtils.toBase36(withChecksum)}`;
            
        } else if (brandKey === 'bmw') {
            const familyIdx = Math.floor(payload / brandKeys.length) % brand.families.length;
            const displIdx = Math.floor(payload / (brandKeys.length * brand.families.length)) % brand.displacements.length;
            const typeIdx = Math.floor(payload / (brandKeys.length * brand.families.length * brand.displacements.length)) % brand.types.length;
            
            const bases = [brandKeys.length, brand.families.length, brand.displacements.length, brand.types.length];
            const indices = [brandIdx, familyIdx, displIdx, typeIdx];
            encoded = EncodingUtils.encodeMultiDimensional(indices, bases);
            const withChecksum = EncodingUtils.addChecksum(encoded ^ payload);
            
            result = `${brand.families[familyIdx]}${brand.displacements[displIdx]}${brand.types[typeIdx]}`;
            return `${brand.name} ${result} ENG-${EncodingUtils.toBase36(withChecksum)}`;
            
        } else if (brandKey === 'vag') {
            const fuelTypeKeys = Object.keys(brand.types);
            const fuelTypeIdx = Math.floor(payload / brandKeys.length) % fuelTypeKeys.length;
            const fuelType = brand.types[fuelTypeKeys[fuelTypeIdx]];
            
            const codeIdx = Math.floor(payload / (brandKeys.length * fuelTypeKeys.length)) % fuelType.codes.length;
            
            const bases = [brandKeys.length, fuelTypeKeys.length, fuelType.codes.length];
            const indices = [brandIdx, fuelTypeIdx, codeIdx];
            encoded = EncodingUtils.encodeMultiDimensional(indices, bases);
            const withChecksum = EncodingUtils.addChecksum(encoded ^ payload);
            
            result = fuelType.codes[codeIdx];
            return `${brand.name} ${result} ENG-${EncodingUtils.toBase36(withChecksum)}`;
            
        } else if (brandKey === 'honda') {
            const familyKeys = Object.keys(brand.families);
            const familyIdx = Math.floor(payload / brandKeys.length) % familyKeys.length;
            const familyKey = familyKeys[familyIdx];
            const family = brand.families[familyKey];
            
            const modelIdx = Math.floor(payload / (brandKeys.length * familyKeys.length)) % family.length;
            
            const bases = [brandKeys.length, familyKeys.length, family.length];
            const indices = [brandIdx, familyIdx, modelIdx];
            encoded = EncodingUtils.encodeMultiDimensional(indices, bases);
            const withChecksum = EncodingUtils.addChecksum(encoded ^ payload);
            
            result = family[modelIdx];
            return `${brand.name} ${result} ENG-${EncodingUtils.toBase36(withChecksum)}`;
            
        } else if (brandKey === 'mercedes') {
            const familyIdx = Math.floor(payload / brandKeys.length) % brand.families.length;
            const variantIdx = Math.floor(payload / (brandKeys.length * brand.families.length)) % brand.variants.length;
            
            const bases = [brandKeys.length, brand.families.length, brand.variants.length];
            const indices = [brandIdx, familyIdx, variantIdx];
            encoded = EncodingUtils.encodeMultiDimensional(indices, bases);
            const withChecksum = EncodingUtils.addChecksum(encoded ^ payload);
            
            result = `${brand.families[familyIdx]}${brand.variants[variantIdx]}`;
            return `${brand.name} ${result} ENG-${EncodingUtils.toBase36(withChecksum)}`;
            
        } else if (brandKey === 'nissan' || brandKey === 'subaru') {
            const familyKeys = Object.keys(brand.families);
            const familyIdx = Math.floor(payload / brandKeys.length) % familyKeys.length;
            const familyKey = familyKeys[familyIdx];
            const family = brand.families[familyKey];
            
            const modelIdx = Math.floor(payload / (brandKeys.length * familyKeys.length)) % family.length;
            
            const bases = [brandKeys.length, familyKeys.length, family.length];
            const indices = [brandIdx, familyIdx, modelIdx];
            encoded = EncodingUtils.encodeMultiDimensional(indices, bases);
            const withChecksum = EncodingUtils.addChecksum(encoded ^ payload);
            
            result = family[modelIdx];
            return `${brand.name} ${result} ENG-${EncodingUtils.toBase36(withChecksum)}`;
            
        } else if (brandKey === 'mazda') {
            const familyKeys = Object.keys(brand.families);
            const familyIdx = Math.floor(payload / brandKeys.length) % familyKeys.length;
            const familyKey = familyKeys[familyIdx];
            const family = brand.families[familyKey];
            
            if (Array.isArray(family)) {
                const modelIdx = Math.floor(payload / (brandKeys.length * familyKeys.length)) % family.length;
                
                const bases = [brandKeys.length, familyKeys.length, family.length];
                const indices = [brandIdx, familyIdx, modelIdx];
                encoded = EncodingUtils.encodeMultiDimensional(indices, bases);
                const withChecksum = EncodingUtils.addChecksum(encoded ^ payload);
                
                result = family[modelIdx];
            } else {
                result = familyKey;
                
                const bases = [brandKeys.length, familyKeys.length];
                const indices = [brandIdx, familyIdx];
                encoded = EncodingUtils.encodeMultiDimensional(indices, bases);
                const withChecksum = EncodingUtils.addChecksum(encoded ^ payload);
            }
            
            return `${brand.name} ${result} ENG-${EncodingUtils.toBase36(EncodingUtils.addChecksum(encoded ^ payload))}`;
            
        } else {
            // Mitsubishi и другие с простым списком
            const modelIdx = Math.floor(payload / brandKeys.length) % brand.families.length;
            
            const bases = [brandKeys.length, brand.families.length];
            const indices = [brandIdx, modelIdx];
            encoded = EncodingUtils.encodeMultiDimensional(indices, bases);
            const withChecksum = EncodingUtils.addChecksum(encoded ^ payload);
            
            result = brand.families[modelIdx];
            return `${brand.name} ${result} ENG-${EncodingUtils.toBase36(withChecksum)}`;
        }
    },

    /**
     * Генерация шины
     * Формат: Brand Model Width/Profile Diameter LoadSpeed TYR-CODE
     */
    generateTire: (payload) => {
        const brandKeys = Object.keys(AutoPartsDictionaries.tires.brands);
        const brandIdx = payload % brandKeys.length;
        const brandKey = brandKeys[brandIdx];
        const brand = AutoPartsDictionaries.tires.brands[brandKey];
        
        const seasonKeys = Object.keys(brand.models);
        const seasonIdx = Math.floor(payload / brandKeys.length) % seasonKeys.length;
        const seasonKey = seasonKeys[seasonIdx];
        const models = brand.models[seasonKey];
        
        const modelIdx = Math.floor(payload / (brandKeys.length * seasonKeys.length)) % models.length;
        const widthIdx = Math.floor(payload / (brandKeys.length * seasonKeys.length * models.length)) % brand.widths.length;
        const profileIdx = Math.floor(payload / (brandKeys.length * seasonKeys.length * models.length * brand.widths.length)) % brand.profiles.length;
        const diameterIdx = Math.floor(payload / (brandKeys.length * seasonKeys.length * models.length * brand.widths.length * brand.profiles.length)) % brand.diameters.length;
        const loadSpeedIdx = Math.floor(payload / (brandKeys.length * seasonKeys.length * models.length * brand.widths.length * brand.profiles.length * brand.diameters.length)) % brand.loadSpeed.length;
        
        const bases = [brandKeys.length, seasonKeys.length, models.length, brand.widths.length, brand.profiles.length, brand.diameters.length, brand.loadSpeed.length];
        const indices = [brandIdx, seasonIdx, modelIdx, widthIdx, profileIdx, diameterIdx, loadSpeedIdx];
        const encoded = EncodingUtils.encodeMultiDimensional(indices, bases);
        const withChecksum = EncodingUtils.addChecksum(encoded ^ payload);
        const code = EncodingUtils.toBase36(withChecksum);
        
        const size = `${brand.widths[widthIdx]}/${brand.profiles[profileIdx]} ${brand.diameters[diameterIdx]} ${brand.loadSpeed[loadSpeedIdx]}`;
        return `${brand.name} ${models[modelIdx]} ${size} TYR-${code}`;
    },

    /**
     * Генерация краски
     * Формат: Manufacturer Code (Name) PNT-CODE
     */
    generatePaint: (payload) => {
        const brandKeys = Object.keys(AutoPartsDictionaries.paints);
        const brandIdx = payload % brandKeys.length;
        const brandKey = brandKeys[brandIdx];
        const brand = AutoPartsDictionaries.paints[brandKey];
        
        const codeIdx = Math.floor(payload / brandKeys.length) % brand.codes.length;
        const nameIdx = Math.floor(payload / (brandKeys.length * brand.codes.length)) % brand.names.length;
        
        const bases = [brandKeys.length, brand.codes.length, brand.names.length];
        const indices = [brandIdx, codeIdx, nameIdx];
        const encoded = EncodingUtils.encodeMultiDimensional(indices, bases);
        const withChecksum = EncodingUtils.addChecksum(encoded ^ payload);
        const code = EncodingUtils.toBase36(withChecksum);
        
        return `${brand.name} ${brand.codes[codeIdx]} (${brand.names[nameIdx]}) PNT-${code}`;
    }
};

/**
 * ПАРСЕР АВТОМОБИЛЬНЫХ КОМПОНЕНТОВ
 */
const AutoPartsParser = {
    markers: {
        sparkPlug: /SPK-([A-Z0-9]+)/,
        filter: /FLT-([A-Z0-9]+)/,
        engine: /ENG-([A-Z0-9]+)/,
        tire: /TYR-([A-Z0-9]+)/,
        paint: /PNT-([A-Z0-9]+)/
    },

    patterns: {
        sparkPlug: /(?:Bosch|NGK|Denso|Champion|Beru)[^\n]*?SPK-[A-Z0-9]+/gi,
        filter: /(?:Mann-Filter|Bosch|Mahle|Knecht|Hengst|Filtron)[^\n]*?FLT-[A-Z0-9]+/gi,
        engine: /(?:Toyota|BMW|VAG|Honda|Mercedes-Benz|Nissan|Subaru|Mitsubishi|Mazda)[^\n]*?ENG-[A-Z0-9]+/gi,
        tire: /(?:Michelin|Bridgestone|Continental|Pirelli|Goodyear|Nokian|Dunlop|Hankook)[^\n]*?TYR-[A-Z0-9]+/gi,
        paint: /(?:Toyota|VAG|BMW|Mercedes-Benz|Ford|Honda|Mazda|Nissan)[^\n]*?PNT-[A-Z0-9]+/gi
    },

    findAllParts: (text) => {
        const found = {};
        
        for (const [type, pattern] of Object.entries(AutoPartsParser.patterns)) {
            const matches = [...text.matchAll(pattern)];
            found[type] = matches.map(m => m[0]);
        }
        
        return found;
    }
};

