/**
 * ГЕНЕРАТОР МОБИЛЬНЫХ УСТРОЙСТВ
 */
const MobileDevicesGenerator = {
    /**
     * Генерация смартфона
     * Формат: Brand Model [Storage] [Color]
     */
    generateSmartphone: (payload) => {
        const brandKeys = Object.keys(MobileDevicesDictionaries.smartphones);
        const brandIdx = payload % brandKeys.length;
        const brandKey = brandKeys[brandIdx];
        const brand = MobileDevicesDictionaries.smartphones[brandKey];
        
        let model, seriesIdx, seriesArray;
        
        if (typeof brand.series === 'object' && !Array.isArray(brand.series)) {
            // Samsung с подкатегориями
            const seriesKeys = Object.keys(brand.series);
            const seriesKeyIdx = Math.floor(payload / brandKeys.length) % seriesKeys.length;
            const seriesKey = seriesKeys[seriesKeyIdx];
            seriesArray = brand.series[seriesKey];
            seriesIdx = Math.floor(payload / (brandKeys.length * seriesKeys.length)) % seriesArray.length;
            model = seriesArray[seriesIdx];
        } else {
            // Простой массив
            seriesArray = brand.series;
            seriesIdx = Math.floor(payload / brandKeys.length) % seriesArray.length;
            model = seriesArray[seriesIdx];
        }
        
        const storageIdx = Math.floor(payload / (brandKeys.length * 100)) % brand.storage.length;
        const colorIdx = Math.floor(payload / (brandKeys.length * 100 * brand.storage.length)) % brand.colors.length;
        
        return `${brand.name} ${model} ${brand.storage[storageIdx]} ${brand.colors[colorIdx]}`;
    },

    /**
     * Генерация планшета
     */
    generateTablet: (payload) => {
        const brandKeys = Object.keys(MobileDevicesDictionaries.tablets);
        const brandIdx = payload % brandKeys.length;
        const brandKey = brandKeys[brandIdx];
        const brand = MobileDevicesDictionaries.tablets[brandKey];
        
        const seriesIdx = Math.floor(payload / brandKeys.length) % brand.series.length;
        const storageIdx = Math.floor(payload / (brandKeys.length * brand.series.length)) % brand.storage.length;
        const colorIdx = Math.floor(payload / (brandKeys.length * brand.series.length * brand.storage.length)) % brand.colors.length;
        
        return `${brand.name} ${brand.series[seriesIdx]} ${brand.storage[storageIdx]} ${brand.colors[colorIdx]}`;
    },

    /**
     * Генерация ноутбука
     */
    generateLaptop: (payload) => {
        const brandKeys = Object.keys(MobileDevicesDictionaries.laptops);
        const brandIdx = payload % brandKeys.length;
        const brandKey = brandKeys[brandIdx];
        const brand = MobileDevicesDictionaries.laptops[brandKey];
        
        const seriesIdx = Math.floor(payload / brandKeys.length) % brand.series.length;
        const storageIdx = Math.floor(payload / (brandKeys.length * brand.series.length)) % brand.storage.length;
        
        if (brandKey === 'apple') {
            const colorIdx = Math.floor(payload / (brandKeys.length * brand.series.length * brand.storage.length)) % brand.colors.length;
            return `${brand.name} ${brand.series[seriesIdx]} ${brand.storage[storageIdx]} ${brand.colors[colorIdx]}`;
        } else {
            const procIdx = Math.floor(payload / (brandKeys.length * brand.series.length)) % brand.processors.length;
            const ramIdx = Math.floor(payload / (brandKeys.length * brand.series.length * brand.processors.length)) % brand.ram.length;
            const colorIdx = Math.floor(payload / (brandKeys.length * brand.series.length * brand.processors.length * brand.ram.length * brand.storage.length)) % brand.colors.length;
            
            return `${brand.name} ${brand.series[seriesIdx]} (${brand.processors[procIdx]}, ${brand.ram[ramIdx]}, ${brand.storage[storageIdx]}) ${brand.colors[colorIdx]}`;
        }
    }
};

